function materialize(spec, index) {
  const slot = EARLY_PLAN[index];
  if (!slot) throw new TypeError(`Missing early archive plan slot ${index + 1}.`);
  return {
    id: slot.id,
    sequence: slot.sequence,
    chapterId: slot.chapterId,
    unlockAfterBeatId: slot.unlockAfterBeatId,
    title: spec.title,
    recordType: spec.recordType,
    custodian: spec.custodian,
    accessNote: spec.accessNote,
    paragraphs: spec.paragraphs,
  };
}

export const ARCHIVE_RECORDS_EARLY = deepFreeze(AUTHORED_EARLY_RECORDS.map(materialize));

const validation = validateArchiveRecordPack(ARCHIVE_RECORDS_EARLY, { expectedGroup: 'early' });
if (!validation.ok) throw new TypeError(validation.errors.join(' '));

export const ARCHIVE_RECORDS_EARLY_METRICS = validation.metrics;
